import { type PropsWithChildren } from 'react';

import { scrollWrapper } from './AnnotationsScrollWrapper.sty.js';

interface AnnotationsScrollWrapperProps {
  height: number | string;
  width: number | string;
}

export const AnnotationsScrollWrapper = ({
  height,
  width,
  children,
}: PropsWithChildren<AnnotationsScrollWrapperProps>) => {
  return (
    <div
      className={scrollWrapper}
      style={{
        width: width,
        height: height,
      }}
    >
      {children}
    </div>
  );
};
